                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"margin-left:40.6pt\\\">&ldquo;Catar Feij&atilde;o</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">Catar feij&atilde;o se limita com escrever:</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">joga-se os gr&atilde;os na &aacute;gua do alguidar</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">e as palavras na folha de papel;</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">e depois, joga-se fora o que boiar.</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">Certo, toda palavra boiar&aacute; no papel,</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">&aacute;gua congelada, por chumbo seu verbo:</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">pois para catar esse feij&atilde;o, soprar nele,</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">e jogar fora o leve e o oco, palha eco&rdquo;.</p>\\n\\n<p style=\\\"margin-left:40.6pt\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\"><strong>Alguidar</strong>: recipiente de barro, metal ou material pl&aacute;stico, usado para tarefas dom&eacute;sticas</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">Em &ldquo;Catar feij&atilde;o&rdquo;, Jo&atilde;o Cabral de Melo Neto revela o(a)</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>valoriza&ccedil;&atilde;o do eu l&iacute;rico, ao extravasar o estado de alma e o sentimento po&eacute;tico.</p>\\n\",\n    \"<p>preocupa&ccedil;&atilde;o com a constru&ccedil;&atilde;o de uma poesia racional contr&aacute;ria ao sentimentalismo choroso.</p>\\n\",\n    \"<p>princ&iacute;pio de que a poesia &eacute; fruto de inspira&ccedil;&atilde;o po&eacute;tica, pois resulta de um trabalho emocional.</p>\\n\",\n    \"<p>influ&ecirc;ncia do Dada&iacute;smo ao escolher palavras, ao acaso, que nada significam para a constru&ccedil;&atilde;o da poesia.</p>\\n\",\n    \"<p>valoriza&ccedil;&atilde;o do pormenor mediante jogos de palavras, sobrecarregando a poesia de figura e de linguagem rebuscada.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
