                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"margin-left: 40px;\\\"><strong>QUINZE DE NOVEMBRO</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">Deodoro todo nos trinques</p>\\n\\n<p style=\\\"text-align:justify\\\">Bate na porta de D&atilde;o Pedro Segundo.</p>\\n\\n<p style=\\\"text-align:justify\\\">&ndash; Seu imperad&ocirc;, d&ecirc; o fora</p>\\n\\n<p style=\\\"text-align:justify\\\">que n&oacute;s queremos tomar conta desta bugiganga.</p>\\n\\n<p style=\\\"text-align:justify\\\">Mande vir os m&uacute;sicos.</p>\\n\\n<p style=\\\"text-align:justify\\\">O imperador bocejando responde:</p>\\n\\n<p style=\\\"text-align:justify\\\">&ndash; Pois n&atilde;o meus filhos n&atilde;o se vexem</p>\\n\\n<p style=\\\"text-align:justify\\\">me deixem cal&ccedil;ar as chinelas</p>\\n\\n<p style=\\\"text-align:justify\\\">podem entrar &agrave; vontade:</p>\\n\\n<p style=\\\"text-align:justify\\\">s&oacute; pe&ccedil;o que n&atilde;o me bulam nas obras completas de Victor Hugo.</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:120.5pt; text-align:right\\\">MENDES, M. <em>Poesia completa e prosa. </em>Rio de Janeiro: Nova Aguilar. 1994.</p>\\n\\n<p style=\\\"margin-left:120.5pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">A poesia de Murilo Mendes dialoga com o ide&aacute;rio po&eacute;tico dos primeiros modernistas. No poema, essa atitude manifesta-se na</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>releitura ir&ocirc;nica de um fato hist&oacute;rico.</p>\\n\",\n    \"<p>vis&atilde;o ufanista de um epis&oacute;dio nacional.</p>\\n\",\n    \"<p>den&uacute;ncia impl&iacute;cita de atitudes autorit&aacute;rias.</p>\\n\",\n    \"<p>isen&ccedil;&atilde;o ideol&oacute;gica do discurso do eu l&iacute;rico.</p>\\n\",\n    \"<p>representa&ccedil;&atilde;o saudosista do regime mon&aacute;rquico.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
