                "comando": null,
                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:justify\\\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; O ADOLESCENTE</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">A vida &eacute; t&atilde;o bela que chega a dar medo.</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">N&atilde;o o medo que paralisa e gela,</p>\\n\\n<p style=\\\"text-align:justify\\\">est&aacute;tua s&uacute;bita,</p>\\n\\n<p style=\\\"text-align:justify\\\">mas</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">esse medo fascinante e fremente de curiosidade que faz</p>\\n\\n<p style=\\\"text-align:justify\\\">o jovem felino seguir para frente farejando o vento</p>\\n\\n<p style=\\\"text-align:justify\\\">ao sair, a primeira vez, da gruta.</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">Medo que ofusca: luz!</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">Cumplicentemente,</p>\\n\\n<p style=\\\"text-align:justify\\\">as folhas contam-te um segredo</p>\\n\\n<p style=\\\"text-align:justify\\\">velho como o mundo:</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">Adolescente, olha! A vida &eacute; nova...</p>\\n\\n<p style=\\\"text-align:justify\\\">A vida &eacute; nova e anda nua</p>\\n\\n<p style=\\\"text-align:justify\\\">&ndash; vestida apenas com o teu desejo!</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:148.85pt; text-align:right\\\">QUINTANA, M. <em>Nariz de vidro. </em>S&atilde;o Paulo: Moderna, 1998.</p>\\n\\n<p style=\\\"margin-left:148.85pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">Ao abordar uma etapa do desenvolvimento humano, o poema mobiliza diferentes estrat&eacute;gias de composi&ccedil;&atilde;o. O principal recurso expressivo empregado para a constru&ccedil;&atilde;o de uma imagem da adolesc&ecirc;ncia &eacute; a</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>hip&eacute;rbole do medo.</p>\\n\",\n    \"<p>met&aacute;fora da est&aacute;tua.</p>\\n\",\n    \"<p>personifica&ccedil;&atilde;o da vida.</p>\\n\",\n    \"<p>ant&iacute;tese entre juventude e velhice.</p>\\n\",\n    \"<p>compara&ccedil;&atilde;o entre desejo e nudez.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
