                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"margin-left:40px; text-align:justify\\\"><strong>MARIA DIAMBA</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">Para n&atilde;o apanhar mais</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">falou que sabia fazer bolos:</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">virou cozinha.</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">Foi outras coisas para que tinha jeito.</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">N&atilde;o falou mais:</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">Viram que sabia fazer tudo,</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">at&eacute; molecas para a Casa-Grande.</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">Depois falou s&oacute;,</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">s&oacute; diante da ventania</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">que ainda vem do Sud&atilde;o;</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">falou que queria fugir</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">dos senhores e das judiarias deste mundo</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">para o sumidouro.</p>\\n\\n<p style=\\\"margin-left:1.0cm\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:155.95pt; text-align:right\\\">LIMA, J. <em>Poemas negros.&nbsp;</em>Rio de Janeiro: Record, 2007.</p>\\n\\n<p style=\\\"margin-left:155.95pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">O poema de Jorge de Lima sintetiza o percurso de vida de Maria Diamba e sua rea&ccedil;&atilde;o ao sistema opressivo da escravid&atilde;o. A resist&ecirc;ncia dessa figura feminina &eacute; assinalada, no texto, pela rela&ccedil;&atilde;o que se faz entre o(a)</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>uso da fala e o desejo de decidir o pr&oacute;prio destino.</p>\\n\",\n    \"<p>explora&ccedil;&atilde;o sexual e a gera&ccedil;&atilde;o de novas escravas.</p>\\n\",\n    \"<p>pr&aacute;tica na cozinha e a inten&ccedil;&atilde;o de ascender socialmente.</p>\\n\",\n    \"<p>prazer de sentir os ventos e a esperan&ccedil;a de voltar &agrave; &Aacute;frica.</p>\\n\",\n    \"<p>medo da morte e a vontade de fugir da viol&ecirc;ncia dos brancos.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
