                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:justify\\\"><img alt=\\\"\\\" src=\\\"data:image/jpeg;base64,\\\" style=\\\"height:267px; margin-bottom:0px; margin-left:0px; margin-right:0px; margin-top:0px; width:185px\\\" /></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:right\\\">Chris Burden. <em>Through the night sofly</em>, 1973. Los Angeles, Calif&oacute;rnia.</p>\\n\\n<p style=\\\"text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">Nas &uacute;ltimas d&eacute;cadas do s&eacute;culo XX, muitos artistas puderam experimentar suportes incomuns para a composi&ccedil;&atilde;o da obra de arte. Tendo como base a imagem anterior e os conceitos em rela&ccedil;&atilde;o &agrave; <em>body art</em>, pode-se afirmar que esse movimento art&iacute;stico caracteriza-se por</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>experimentar, pictoricamente, o corpo como representa&ccedil;&atilde;o da anatomia humana.</p>\\n\",\n    \"<p>estabelecer e cultivar tra&ccedil;os culturais, cren&ccedil;as e rituais.</p>\\n\",\n    \"<p>fazer do corpo mat&eacute;ria e interven&ccedil;&atilde;o para o trabalho art&iacute;stico.</p>\\n\",\n    \"<p>destacar o corpo como tem&aacute;tica sendo explorado na pintura realista.</p>\\n\",\n    \"<p>compreender a autonomia do corpo no contexto da obra.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
