                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:center\\\"><strong>RETRATO DO ARTISTA QUANDO COISA</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">A maior riqueza</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">do homem</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">&eacute; sua incompletude.</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">Nesse ponto</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">sou abastado.</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">Palavras que me aceitam</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">como sou</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">&mdash; eu n&atilde;o aceito.</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">N&atilde;o aguento ser apenas</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">um sujeito que abre</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">portas, que puxa</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">v&aacute;lvulas, que olha o</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">rel&oacute;gio, que compra p&atilde;o</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">&agrave;s 6 da tarde, que vai</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">l&aacute; fora, que aponta l&aacute;pis,</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">que v&ecirc; a uva etc. etc.</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">Perdoai. Mas eu</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">preciso ser Outros.</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">Eu penso</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">renovar o homem</p>\\n\\n<p style=\\\"margin-left:70.9pt\\\">usando borboletas.</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:70.9pt; text-align:right\\\">BARROS, Manoel. <em>O retrato do Artista Quando Coisa.&nbsp;</em>Rio de Janeiro: Record, 1998.</p>\\n\\n<p style=\\\"margin-left:70.9pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">Levando em conta as rela&ccedil;&otilde;es de sentido presentes nesse texto de Manoel de Barros, &eacute; correto afirmar que o conte&uacute;do tem&aacute;tico geral do poema se estabelece na seguinte oposi&ccedil;&atilde;o sem&acirc;ntica:</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>humaniza&ccedil;&atilde;o <em>versus</em> coisifica&ccedil;&atilde;o.</p>\\n\",\n    \"<p>riqueza <em>versus</em> pobreza.</p>\\n\",\n    \"<p>a&ccedil;&atilde;o <em>versus</em> in&eacute;rcia.</p>\\n\",\n    \"<p>grandeza <em>versus</em> pequenez.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
