                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:justify\\\">VIII</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">O poeta</p>\\n\\n<p style=\\\"text-align:justify\\\">declina de toda responsabilidade</p>\\n\\n<p style=\\\"text-align:justify\\\">na marcha do mundo capitalista</p>\\n\\n<p style=\\\"text-align:justify\\\">e com suas palavras, intui&ccedil;&otilde;es, s&iacute;mbolos e outras armas</p>\\n\\n<p style=\\\"text-align:justify\\\">prometa ajudar</p>\\n\\n<p style=\\\"text-align:justify\\\">a destru&iacute;-lo</p>\\n\\n<p style=\\\"text-align:justify\\\">como uma pedreira, uma floresta</p>\\n\\n<p style=\\\"text-align:justify\\\">um verme.</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:5cm; text-align:right\\\">ANDRADE, Carlos Drummond.&nbsp;<em>Nosso Tempo.</em> In: <em>A rosa do povo.</em></p>\\n\\n<p style=\\\"margin-left:5cm; text-align:right\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align:justify\\\">Atente ao que &eacute; dito sobre a &uacute;ltima parte do poema Nosso tempo, de Drummond de Andrade.</p>\\n\\n<p style=\\\"margin-left:17.0pt\\\">I. &Eacute; not&oacute;ria a postura engajada do poeta: os tr&ecirc;s primeiros versos estabelecem uma dicotomia social com o restante da estrofe.</p>\\n\\n<p style=\\\"margin-left:17.0pt\\\">II. Em &ldquo;destru&iacute;-lo&rdquo;, denotamos um exemplo predominante de fun&ccedil;&atilde;o emotiva.</p>\\n\\n<p style=\\\"margin-left:17.0pt\\\">III. O metapoema heterom&eacute;trico de Drummond, eivado de objetividade, afasta possibilidades conotativas.</p>\\n\\n<p style=\\\"margin-left:17.0pt\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">Est&aacute; correto o que se diz</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>apenas em I.</p>\\n\",\n    \"<p>apenas em I e II.</p>\\n\",\n    \"<p>apenas em I e III.</p>\\n\",\n    \"<p>em I, II e III.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
