                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align: justify; margin-left: 80px;\\\"><strong>PO&Eacute;TICA</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">De manh&atilde; escure&ccedil;o</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">De dia tardo</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">De tarde anoite&ccedil;o</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">De noite ardo.</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">A oeste a morte</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Contra quem vivo</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Do sul cativo</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">O este &eacute; meu norte.</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Outros que contem</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Passo por passo:</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Eu morro ontem</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Nas&ccedil;o amanh&atilde;</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">Ando onde h&aacute; espa&ccedil;o:</p>\\n\\n<p style=\\\"text-align: justify; margin-left: 40px;\\\">&mdash; Meu tempo &eacute; quando.</p>\\n\\n<p style=\\\"text-align: justify;\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align: right;\\\">MORAES, Vinicius de.&nbsp;<em>Antologia Po&eacute;tica. </em>Rio de Janeiro: Companhia das Letras, 1954.</p>\\n\\n<p style=\\\"margin-left:99.25pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">No soneto apresentado, a percep&ccedil;&atilde;o de tempo e espa&ccedil;o pelo poeta ocorre de maneira surpreendente. Ao romper com o encadeamento l&oacute;gico, o poema</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>expressa, em tom nost&aacute;lgico, a ang&uacute;stia pela incapacidade de adaptar-se ao mundo.</p>\\n\",\n    \"<p>valoriza uma atitude libert&aacute;ria, que mant&eacute;m rela&ccedil;&otilde;es flex&iacute;veis com o tempo e com o espa&ccedil;o.</p>\\n\",\n    \"<p>confirma uma vis&atilde;o m&iacute;stica, na qual o tempo e o espa&ccedil;o ganham contornos divinizados.</p>\\n\",\n    \"<p>faz uma cr&iacute;tica de cunho social para denunciar a onipresen&ccedil;a espa&ccedil;o-temporal na sociedade.</p>\\n\",\n    \"<p>estabelece, metaforicamente, uma rela&ccedil;&atilde;o entre a brevidade da vida e a paix&atilde;o humana.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
