                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align: justify; margin-left: 80px;\\\"><strong>CENINHA CASEIRA</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">A fam&iacute;lia reunida</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">No almo&ccedil;o do domingo:</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">&mdash; M&atilde;e, me d&aacute; laranjada.</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">&mdash; A laranja se acabou.</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">&mdash; M&atilde;e, me d&aacute; limonada.</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">&mdash; O lim&atilde;o se acabou.</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">No almo&ccedil;o de domingo</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">Da fam&iacute;lia reunida</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">Ningu&eacute;m pede amorada,</p>\\n\\n<p style=\\\"margin-left: 40px;\\\">Que o amor, tamb&eacute;m se acabou.</p>\\n\\n<p>&nbsp;</p>\\n\\n<p style=\\\"text-align: right;\\\">ANTUNES, S. <em>Rel&oacute;gio da sala. </em>S&atilde;o Paulo: Selecionada, 1986.</p>\\n\\n<p style=\\\"margin-left:5cm; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">Como inten&ccedil;&atilde;o comunicativa, o autor utilizou o voc&aacute;bulo &ldquo;amorada&rdquo; para</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>fazer men&ccedil;&atilde;o &agrave; fruta amora, como comparativo com as outras frutas citadas no texto.</p>\\n\",\n    \"<p>utilizar uma palavra existente na L&iacute;ngua de car&aacute;ter bastante enf&aacute;tico no texto.</p>\\n\",\n    \"<p>tornar o termo incompreens&iacute;vel por n&atilde;o apresentar elementos estruturais que o definam.</p>\\n\",\n    \"<p>usar da criatividade com um neologismo para expressar a situa&ccedil;&atilde;o do ambiente familiar.</p>\\n\",\n    \"<p>centrar-se no afeto que vem do amor familiar.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
