                "comando": null,
                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:justify\\\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;XIII</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">&ldquo;Ora (direis) ouvir estrelas! Certo</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Perdeste o senso!&rdquo; E eu vos direi, no entanto,</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Que, para ouvi-las, muita vez desperto</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">E abro as janelas, p&aacute;lido de espanto&hellip;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">E conversamos toda a noite, enquanto</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">A Via-L&aacute;ctea, como um p&aacute;lio aberto,</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Cintila. E, ao vir do sol, saudoso e em pranto,</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Inda as procuro pelo c&eacute;u deserto.</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Direis agora: &ldquo;Tresloucado amigo!</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Que conversas com elas? Que sentido</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Tem o que dizem, quando est&atilde;o contigo?&rdquo;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">E eu vos direi: &ldquo;Amai para entend&ecirc;-las!</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Pois s&oacute; quem ama pode ter ouvido</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">Capaz de ouvir e de entender estrelas.&rdquo;</p>\\n\\n<p style=\\\"margin-left:35.45pt\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:70.9pt; text-align:right\\\">BILAC, Olavo. <em>Antologia: Poesias.</em> Martin Claret, 2002. p. 37-55. Via-L&aacute;ctea.</p>\\n\\n<p style=\\\"text-align: right;\\\">Dispon&iacute;vel em: http://www.dominiopublico.gov.br/download/texto/bv000289.pdf. Acesso em: 19 ago. 2019.</p>\\n\\n<p style=\\\"margin-left:70.9pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">A palavra &ldquo;pois&rdquo;, usada em &ldquo;Pois s&oacute; quem ama pode ter ouvido&rdquo; (verso 13),</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>exprime a consequ&ecirc;ncia dos h&aacute;bitos cotidianos do poeta de ouvir e entender estrelas.</p>\\n\",\n    \"<p>tem uma fun&ccedil;&atilde;o de justifica&ccedil;&atilde;o das raz&otilde;es pelas quais o poeta &eacute; capaz de ouvir e entender estrelas.</p>\\n\",\n    \"<p>traz em si uma ideia de contraponto ao enlevo po&eacute;tico descrito no poema.</p>\\n\",\n    \"<p>expressa a ideia da finalidade primeira do poeta enamorado, que &eacute; ouvir e entender estrelas.</p>\\n\",\n    \"<p>estabelece a ideia de altern&acirc;ncia, mas sem rela&ccedil;&atilde;o de equival&ecirc;ncia nos versos do texto.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
