                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;La Autoridad Palestina ha estado enfrentando una crisis financiera severa despu&eacute;s de que Israel decidiera en febrero reducir el pago de los ingresos fiscales en la cantidad que la Autoridad Palestina paga a los prisioneros y familias palestinas de los palestinos muertos a manos de Israel.</p>\\n\\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Bajo un tratado econ&oacute;mico alcanzado en 1995 entre Israel y los palestinos, Israel recauda los impuestos del comercio palestino en nombre de la Autoridad Palestina, a la cual se los entrega para que pague los salarios de sus empleados.</p>\\n\\n<p style=\\\"text-align:right\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:99.25pt; text-align:right\\\">Dispon&iacute;vel em: http://spanish.xinhuanet.com/. Acesso em: 3 fev. 2020 (fragmento)</p>\\n\\n<p style=\\\"margin-left:99.25pt; text-align:right\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">En el fragmento &ldquo;[...] se los entrega [&hellip;]&rdquo;, en el segundo p&aacute;rrafo, la part&iacute;cula &ldquo;<strong>se</strong>&rdquo;, se refiere a</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>los impuestos.</p>\\n\",\n    \"<p>los ingresos fiscales.</p>\\n\",\n    \"<p>la Autoridad Palestina.</p>\\n\",\n    \"<p>Israel.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
