                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:justify\\\">As&iacute; como el fragmento &ldquo;me gusta estar solo&rdquo; la utilizaci&oacute;n del verbo gustar est&aacute; correctamente empleada, se&ntilde;ala con V las proposiciones verdaderas y con F las proposiciones falsas, con relaci&oacute;n al uso adecuado del verbo gustar y su conjugaci&oacute;n. Enseguida, marca la secuencia correcta.</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"margin-left:25.5pt\\\">(&nbsp; &nbsp;) &ldquo;A los adolescentes tambi&eacute;n les gustan discutir sobre econom&iacute;a internacional.&rdquo;</p>\\n\\n<p style=\\\"margin-left:25.5pt\\\">(&nbsp; &nbsp;) &ldquo;No me gusta cuando veo maltrato animal, me quedo horrorizada.&rdquo;</p>\\n\\n<p style=\\\"margin-left:25.5pt\\\">(&nbsp; &nbsp;) &ldquo;Al primo de Juan le gusta las casas que cuidan de los perros abandonados.&rdquo;</p>\\n\\n<p style=\\\"margin-left:25.5pt\\\">(&nbsp; &nbsp;) &ldquo;A mis vecinos les gusta mucho salir a pasear con sus mascotas.&rdquo;</p>\\n\\n<p style=\\\"margin-left:25.5pt\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>F &ndash; F &ndash; V &ndash; F</p>\\n\",\n    \"<p>V &ndash; V &ndash; V &ndash; F</p>\\n\",\n    \"<p>V &ndash; F &ndash; V &ndash; V</p>\\n\",\n    \"<p>F &ndash; V &ndash; F &ndash; V</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
