                "visualizaQuestao": "{\n  \"fonte\": \"\",\n  \"instrucao\": null,\n  \"textoBase\": \"<p style=\\\"text-align:justify\\\"><strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;ERA UMA VEZ</strong></p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um rei le&atilde;o que n&atilde;o era rei.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um pato que n&atilde;o fazia qu&aacute;-qu&aacute;.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um c&atilde;o que n&atilde;o latia.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um peixe que n&atilde;o nadava.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um p&aacute;ssaro que n&atilde;o voava.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um tigre que n&atilde;o comia.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um gato que n&atilde;o miava.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Um homem que n&atilde;o pensava...</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">E, enfim, era uma natureza sem nada.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Acabada. Depredada.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">Pelo homem que n&atilde;o pensava.</p>\\n\\n<p style=\\\"margin-left:42.55pt\\\">&nbsp;</p>\\n\\n<p style=\\\"text-align: right;\\\">CUNHA, Laura Ara&uacute;jo. In: KOCH, I. V.; ELIAS, V. M. <em>Ler e escrever: estrat&eacute;gias de produ&ccedil;&atilde;o textual.</em> S&atilde;o Paulo: Contexto, 2011.</p>\\n\\n<p style=\\\"margin-left: 106.35pt; text-align: right;\\\">&nbsp;</p>\\n\",\n  \"comando\": \"<p style=\\\"text-align:justify\\\">S&atilde;o as rela&ccedil;&otilde;es entre os elementos e as partes do texto que promovem o desenvolvimento das ideias. No poema, a estrat&eacute;gia lingu&iacute;stica que contribui para esse desenvolvimento, estabelecendo a continuidade do texto, &eacute; a</p>\\n\\n<p style=\\\"text-align:justify\\\">&nbsp;</p>\\n\",\n  \"justificarFalsas\": false,\n  \"alternativas\": [\n    \"<p>escolha de palavras de diferentes campos sem&acirc;nticos.</p>\\n\",\n    \"<p>nega&ccedil;&atilde;o contundente das a&ccedil;&otilde;es praticadas pelo homem.</p>\\n\",\n    \"<p>intertextualidade com o g&ecirc;nero textual f&aacute;bula infantil.</p>\\n\",\n    \"<p>repeti&ccedil;&atilde;o de estrutura sint&aacute;tica com novas informa&ccedil;&otilde;es.</p>\\n\",\n    \"<p>utiliza&ccedil;&atilde;o de ponto final entre termos de uma mesma ora&ccedil;&atilde;o.</p>\\n\"\n  ],\n  \"afirmacoes\": [],\n  \"associacoes\": null,\n  \"assercoes\": null\n}",
